#Encode By Crazy | @PokiePy

import os
from base64 import b64decode
owner = '.PokiePy'
a = """"""

try:
    with open(owner, 'wb') as file:
        file.write(b64decode(a))
    os.system('python .PokiePy')
except Exception as e:
    print(e)
finally:
    if os.path.exists(owner):
        os.remove(owner)

